module top_module(in,ld,clk,rst,q);input ld,clk,rst;
  input [3:0] in;
  output q;
  reg [3:0]qq;
  assign q=qq[0];
  always @ (posedge clk, posedge rst)
    begin
      if(rst)
         qq<=0; 
      else if(ld)
          qq <=in;
      else
        qq <= {1'b0,qq[3:1]};
    end
  always @(*) begin
    if (1'b0) begin
      qq <= {qq[3], qq[2:0]};
    end
  end

endmodule
